// Combined extraction and duplicate check to ensure proper flow
const inputData = $input.item.json;

if (!inputData.body || !inputData.body.data) {
  throw new Error('Invalid webhook payload');
}

const data = inputData.body.data;
const message = data.message || {};
const key = data.key || {};

// Função para extrair o número de telefone corretamente
function extractPhoneNumber(data) {
  // Prioridade 1: usar senderPn se existir (v2.3+)
  if (data.senderPn) {
    console.log('Using senderPn field (v2.3+):', data.senderPn);
    return formatBrazilianPhone(data.senderPn);
  }

  // Prioridade 2: usar remoteJid (v2.2.x e fallback)
  const key = data.key || {};
  if (key.remoteJid) {
    console.log('Using remoteJid field (fallback):', key.remoteJid);
    return extractFromRemoteJid(key.remoteJid);
  }

  console.log('WARNING: No phone number field available');
  return '';
}

// Função para formatar número brasileiro
function formatBrazilianPhone(phone) {
  let cleaned = String(phone).replace(/\D/g, '');

  // Remove código do país se presente
  if (cleaned.startsWith('55') && cleaned.length >= 12) {
    cleaned = cleaned.substring(2);
  }

  // Validação: deve ter 10-11 dígitos (DDD + número)
  if (!/^\d{10,11}$/.test(cleaned)) {
    console.log('WARNING: Phone number format unexpected:', cleaned);
  }

  return cleaned;
}

// Função para extrair de remoteJid
function extractFromRemoteJid(remoteJid) {
  if (!remoteJid) return '';

  // Remove @s.whatsapp.net ou @g.us (grupos)
  let cleaned = remoteJid.replace(/@[sg]\.(?:whatsapp\.net|us)$/, '');

  // Aplica formatação padrão
  return formatBrazilianPhone(cleaned);
}

// Build output
const output = {
  phone_number: extractPhoneNumber(data),
  whatsapp_name: data.pushName || '',
  message_id: key.id || `gen_${Date.now()}`,
  message_type: 'text',
  content: '',
  media_url: null,
  // Initialize duplicate flag as false
  is_duplicate: false,
  needs_save: true
};

// Log para debug
console.log('Evolution API Data:', {
  senderPn: data.senderPn || 'not present',
  remoteJid: key.remoteJid || 'not present'
});
console.log('Phone number extraído:', output.phone_number);

// Extract content based on message type
if (message.conversation) {
  output.content = message.conversation;
} else if (message.extendedTextMessage) {
  output.content = message.extendedTextMessage.text || '';
} else if (message.imageMessage) {
  output.message_type = 'image';
  output.media_url = message.imageMessage.url || '';
  output.content = message.imageMessage.caption || '[Imagem]';
} else if (message.audioMessage) {
  output.message_type = 'audio';
  output.content = '[Áudio]';
} else if (message.documentMessage) {
  output.message_type = 'document';
  output.content = message.documentMessage.fileName || '[Documento]';
}

return output;

// Merge duplicate check result with message data
const messageData = $node["Extract Message Data"].json;
const queryResult = $input.all();

// Check if we have a duplicate
let isDuplicate = false;
if (queryResult && queryResult.length > 0) {
  // Check if the result has an id field
  const firstResult = queryResult[0];
  if (firstResult && firstResult.json && firstResult.json.id) {
    isDuplicate = true;
  }
}

// Return merged data with duplicate status
return {
  ...messageData,
  is_duplicate: isDuplicate,
  needs_save: !isDuplicate
};

// Prepara os dados para passar ao Workflow 02
const messageData = $node["Merge Results"].json;

// Garantir que o phone_number seja passado corretamente
const phone_number = messageData.phone_number || '';

if (!phone_number) {
  throw new Error('Phone number is required but was not extracted correctly');
}

console.log('Passando para Workflow 02:', {
  phone_number: phone_number,
  whatsapp_name: messageData.whatsapp_name
});

return {
  phone_number: phone_number,
  whatsapp_name: messageData.whatsapp_name || '',
  message: messageData.content || '',
  message_type: messageData.message_type || 'text',
  media_url: messageData.media_url || null,
  message_id: messageData.message_id || '',
  timestamp: new Date().toISOString()
};
